import React, { useState, useEffect, useRef } from 'react';
import { slotAPI, doubtAPI, authAPI } from '../services/api';
import io from 'socket.io-client';

const AskDoubtPage = () => {
  const [doubts, setDoubts] = useState([]);
  const [mySlots, setMySlots] = useState([]);
  const [staffList, setStaffList] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [view, setView] = useState('ask');
  const [successMessage, setSuccessMessage] = useState('');
  const socketRef = useRef(null);

  const [formData, setFormData] = useState({
    subject: '',
    targetStaffId: '',
    question: '',
    requestSlot: false,
  });

  const [joinLink, setJoinLink] = useState('');

  const subjects = ['Physics', 'Chemistry', 'Mathematics', 'Biology', 'Computer Science', 'English'];

  useEffect(() => {
    fetchStaff();
    fetchData();
  }, []);

  useEffect(() => {
    socketRef.current = io('http://localhost:5000', {
      auth: {
        token: sessionStorage.getItem('token') || localStorage.getItem('token'),
      },
    });

    socketRef.current.on('doubt_updated', () => {
      fetchData();
    });

    socketRef.current.on('slot_updated', () => {
      fetchData();
    });

    return () => {
      socketRef.current.off('doubt_updated');
      socketRef.current.off('slot_updated');
      socketRef.current.disconnect();
    };
  }, []);

  const fetchStaff = async () => {
    try {
      const res = await authAPI.getAllStaff();
      setStaffList(res.data.staff || []);
    } catch (err) {
      console.error('Failed to fetch staff list');
    }
  };

  const fetchData = async () => {
    setLoading(true);
    try {
      const [doubtsRes, slotsRes] = await Promise.all([
        doubtAPI.getMyDoubts(),
        slotAPI.getMySlots(),
      ]);
      setDoubts(doubtsRes.data.doubts || []);
      setMySlots(slotsRes.data.slots || []);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const showSuccess = (msg) => {
    setSuccessMessage(msg);
    setTimeout(() => setSuccessMessage(''), 3000);
  };

  const showError = (msg) => {
    setError(msg);
    setTimeout(() => setError(''), 4000);
  };

  const handleAskDoubt = async (e) => {
    e.preventDefault();
    if (!formData.subject && !formData.targetStaffId) {
       showError("Please select either a subject or a specific staff member.");
       return;
    }
    try {
      await doubtAPI.createDoubt(formData);
      showSuccess('Doubt submitted successfully!');
      setFormData({ subject: '', targetStaffId: '', question: '', requestSlot: false });
      setView('doubts');
      fetchData();
    } catch (err) {
      showError(err.response?.data?.error || 'Failed to submit doubt');
    }
  };

  const handleJoinSlot = async (e) => {
    e.preventDefault();
    if (!joinLink) return;
    try {
      const linkId = joinLink.split('/').pop();
      await slotAPI.joinSlot(linkId);
      showSuccess('Successfully joined the session!');
      setJoinLink('');
      setView('slots');
      fetchData();
    } catch (err) {
      showError(err.response?.data?.error || 'Failed to join session');
    }
  };

  const handleConfirmSlot = async (slotId) => {
    try {
      await slotAPI.confirmSlot(slotId);
      showSuccess('Session confirmed successfully!');
      fetchData();
    } catch (err) {
      showError(err.response?.data?.error || 'Failed to confirm session');
    }
  };

  const formatDateTime = (date, time) => {
    try {
      return `${new Date(date).toLocaleDateString()} at ${time}`;
    } catch {
      return `${date} at ${time}`;
    }
  };

  return (
    <>
      <div className="animated-bg">
        <div className="blob blob-1"></div>
        <div className="blob blob-2"></div>
        <div className="blob blob-3"></div>
      </div>
      <div className="page-content">
        <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '2rem', gap: '1rem' }}>
          <div>
            <h1 className="dashboard-title">Ask a Doubt & Sessions</h1>
            <p className="dashboard-subtitle">Submit your questions to teachers and track scheduled sessions.</p>
          </div>
        </div>

        {error && (
          <div style={{ background: 'rgba(239, 68, 68, 0.2)', border: '1px solid var(--status-danger)', padding: '1rem', borderRadius: '12px', marginBottom: '1rem', display: 'flex', justifyContent: 'space-between' }}>
            <span>{error}</span>
            <button onClick={() => setError('')} style={{ color: 'white', background: 'transparent', border: 'none', cursor: 'pointer' }}>x</button>
          </div>
        )}

        {successMessage && (
          <div style={{ background: 'rgba(34, 197, 94, 0.2)', border: '1px solid var(--status-success)', padding: '1rem', borderRadius: '12px', marginBottom: '1rem', display: 'flex', justifyContent: 'space-between' }}>
            <span>{successMessage}</span>
            <button onClick={() => setSuccessMessage('')} style={{ color: 'white', background: 'transparent', border: 'none', cursor: 'pointer' }}>x</button>
          </div>
        )}

        <div style={{ display: 'flex', gap: '1rem', marginBottom: '2rem', overflowX: 'auto', paddingBottom: '0.5rem' }}>
          {['ask', 'doubts', 'slots', 'join'].map(tab => (
            <button
              key={tab}
              style={{
                padding: '0.5rem 1.5rem',
                borderRadius: '999px',
                border: 'none',
                fontWeight: 'bold',
                whiteSpace: 'nowrap',
                background: view === tab ? 'var(--accent-primary)' : 'var(--bg-surface-solid)',
                color: view === tab ? 'var(--text-main)' : 'var(--text-muted)',
                cursor: 'pointer'
              }}
              onClick={() => setView(tab)}
            >
              {tab === 'ask' && 'Ask a Doubt'}
              {tab === 'doubts' && `My Doubts (${doubts.length})`}
              {tab === 'slots' && `My Sessions (${mySlots.length})`}
              {tab === 'join' && 'Join via Link'}
            </button>
          ))}
        </div>

        {loading ? (
          <div style={{ padding: '3rem', textAlign: 'center', color: 'var(--text-muted)' }}>Loading...</div>
        ) : (
          <>
            {view === 'ask' && (
              <div className="island-card" style={{ padding: '2rem', maxWidth: '600px', margin: '0 auto' }}>
                <h3 style={{ marginBottom: '1.5rem' }}>Submit a new doubt</h3>
                <form onSubmit={handleAskDoubt} style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>

                  <div style={{ display: 'flex', gap: '1rem' }}>
                    <div style={{ flex: 1 }}>
                      <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 'bold' }}>Subject</label>
                      <select 
                        value={formData.subject} 
                        onChange={(e) => setFormData({...formData, subject: e.target.value})}
                        style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: 'var(--bg-document)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                      >
                        <option value="">Select Generic Subject</option>
                        {subjects.map(sub => <option key={sub} value={sub}>{sub}</option>)}
                      </select>
                    </div>

                    <div style={{ flex: 1 }}>
                      <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 'bold' }}>Specific Staff (Optional)</label>
                      <select 
                        value={formData.targetStaffId} 
                        onChange={(e) => setFormData({...formData, targetStaffId: e.target.value})}
                        style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: 'var(--bg-document)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                      >
                        <option value="">Anyone</option>
                        {staffList.map(staff => <option key={staff._id} value={staff._id}>{staff.name} ({staff.subject})</option>)}
                      </select>
                    </div>
                  </div>

                  <div>
                    <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 'bold' }}>Your Question</label>
                    <textarea 
                      required
                      rows="4"
                      placeholder="Type your question here..."
                      value={formData.question}
                      onChange={(e) => setFormData({...formData, question: e.target.value})}
                      style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: 'var(--bg-document)', border: '1px solid rgba(255,255,255,0.1)', color: 'white', resize: 'vertical' }}
                    ></textarea>
                  </div>

                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <input 
                      type="checkbox" 
                      id="optSlot" 
                      checked={formData.requestSlot}
                      onChange={(e) => setFormData({...formData, requestSlot: e.target.checked})}
                      style={{ width: '1.2rem', height: '1.2rem', accentColor: 'var(--accent-primary)' }}
                    />
                    <label htmlFor="optSlot" style={{ cursor: 'pointer' }}>Request a live interactive session (Slot)</label>
                  </div>

                  <button className="btn btn-primary" type="submit" disabled={!formData.question || (!formData.subject && !formData.targetStaffId)}>
                    Submit Doubt
                  </button>
                </form>
              </div>
            )}

            {view === 'join' && (
              <div className="island-card" style={{ padding: '2rem', maxWidth: '600px', margin: '0 auto', textAlign: 'center' }}>
                <h3 style={{ marginBottom: '1.5rem' }}>Join an existing session</h3>
                <p style={{ color: 'var(--text-muted)', marginBottom: '1.5rem' }}>If a friend shared a session link with you, paste the code here to join their group session.</p>
                <form onSubmit={handleJoinSlot} style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                  <input 
                    type="text" 
                    placeholder="Enter Shareable Link Code (e.g. 5f4dcc3...)"
                    value={joinLink}
                    onChange={(e) => setJoinLink(e.target.value)}
                    required
                    style={{ width: '100%', padding: '1rem', borderRadius: '8px', background: 'var(--bg-document)', border: '1px solid rgba(255,255,255,0.1)', color: 'white', textAlign: 'center' }}
                  />
                  <button className="btn btn-primary" type="submit" disabled={!joinLink}>
                    Join Session
                  </button>
                </form>
              </div>
            )}

            {view === 'doubts' && (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                {doubts.length === 0 ? (
                  <p style={{ color: 'var(--text-muted)' }}>You haven't asked any doubts yet.</p>
                ) : doubts.map(doubt => (
                  <div key={doubt._id} className="island-card" style={{ padding: '1.5rem' }}>
                     <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' }}>
                        <span style={{ fontWeight: 'bold' }}>{doubt.subject} {doubt.targetStaffId?.name ? `→ ${doubt.targetStaffId.name}` : ''}</span>
                        <span style={{ 
                          padding: '0.25rem 0.75rem', borderRadius: '999px', fontSize: '0.85rem', fontWeight: 'bold',
                          background: doubt.status === 'Resolved' ? 'rgba(34,197,94,0.2)' : doubt.status === 'Slot Scheduled' ? 'rgba(56,189,248,0.2)' : 'rgba(255,255,255,0.1)',
                          color: doubt.status === 'Resolved' ? 'var(--status-success)' : doubt.status === 'Slot Scheduled' ? 'var(--accent-primary)' : 'var(--text-muted)'
                        }}>
                          {doubt.status}
                        </span>
                     </div>
                     <p style={{ marginBottom: '1rem' }}>{doubt.question}</p>

                     <div style={{ fontSize: '0.85rem', color: 'var(--text-muted)', display: 'flex', justifyContent: 'space-between' }}>
                        <span>Requested Slot: {doubt.requestSlot ? 'Yes' : 'No'}</span>
                        <span>Asked on {new Date(doubt.createdAt).toLocaleDateString()}</span>
                     </div>
                  </div>
                ))}
              </div>
            )}

            {view === 'slots' && (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                {mySlots.length === 0 ? (
                  <p style={{ color: 'var(--text-muted)' }}>You don't have any upcoming sessions.</p>
                ) : mySlots.map(slot => (
                  <div key={slot._id} className="island-card" style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                     <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                        <div>
                          <h3 style={{ margin: '0 0 0.5rem 0' }}>{slot.topic}</h3>
                          <p style={{ margin: 0, color: 'var(--text-muted)' }}>Host: {slot.staffId?.name} ({slot.staffId?.subject})</p>
                        </div>
                        <div style={{ textAlign: 'right' }}>
                          <div style={{ fontWeight: 'bold', fontSize: '1.1rem' }}>{formatDateTime(slot.date, slot.time)}</div>
                          <div style={{ fontSize: '0.85rem', color: 'var(--text-muted)' }}>{slot.duration} mins</div>
                        </div>
                     </div>
                     {slot.notes && (
                       <div style={{ background: 'var(--bg-document)', padding: '1rem', borderRadius: '8px', fontSize: '0.9rem' }}>
                          <strong>Notes: </strong> {slot.notes}
                       </div>
                     )}
                     <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '0.5rem' }}>
                        <span style={{ 
                            padding: '0.25rem 0.75rem', borderRadius: '999px', fontSize: '0.85rem', fontWeight: 'bold',
                            background: slot.status === 'Confirmed' ? 'rgba(34,197,94,0.2)' : 'rgba(245,158,11,0.2)',
                            color: slot.status === 'Confirmed' ? 'var(--status-success)' : 'var(--status-warning)'
                          }}>
                            {slot.status}
                        </span>

                        <div style={{ display: 'flex', gap: '0.5rem' }}>
                           <button 
                             style={{ padding: '0.5rem 1rem', borderRadius: '8px', background: 'transparent', border: '1px solid rgba(255,255,255,0.2)', color: 'white', cursor: 'pointer' }}
                             onClick={() => { navigator.clipboard.writeText(slot.shareableLink); showSuccess('Link copied to clipboard!'); }}
                           >
                             Copy Invite Link
                           </button>
                           {slot.status === 'Pending Student Confirmation' && (
                             <button className="btn btn-primary" style={{ padding: '0.5rem 1rem', borderRadius: '8px' }} onClick={() => handleConfirmSlot(slot._id)}>
                               Confirm Attendance
                             </button>
                           )}
                        </div>
                     </div>
                  </div>
                ))}
              </div>
            )}
          </>
        )}
      </div>
    </>
  );
};

export default AskDoubtPage;
